/**
 * @summary Get all users (admin only)
 */
export const getAdminGetUsersUrl = (params?: AdminGetUsersParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/admin/users?${stringifiedParams}`
    : `/api/admin/users`;
};

export const adminGetUsers = async (
  params?: AdminGetUsersParams,
  options?: RequestInit,
): Promise<AdminUsersResponse> => {
  return customFetch<AdminUsersResponse>(getAdminGetUsersUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getAdminGetUsersQueryKey = (params?: AdminGetUsersParams) => {
  return [`/api/admin/users`, ...(params ? [params] : [])] as const;
};

export const getAdminGetUsersQueryOptions = <
  TData = Awaited<ReturnType<typeof adminGetUsers>>,
  TError = ErrorType<ErrorResponse>,
>(
  params?: AdminGetUsersParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof adminGetUsers>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getAdminGetUsersQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof adminGetUsers>>> = ({
    signal,
  }) => adminGetUsers(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof adminGetUsers>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type AdminGetUsersQueryResult = NonNullable<
  Awaited<ReturnType<typeof adminGetUsers>>
>;
export type AdminGetUsersQueryError = ErrorType<ErrorResponse>;

